// Parse Gemini's email JSON
let raw = $json.choices[0].message.content;
raw = raw.replace(/```json/g, '').replace(/```/g, '').trim();
const email = JSON.parse(raw);

// Carry the score data forward so logging + Gmail have everything in one place
const scoreData = $('Score Data').item.json;

return {
  subject: email.subject,
  body: email.body,
  score: scoreData.score,
  reasoning: scoreData.reasoning,
  talking_points: scoreData.talking_points,
  company: scoreData.company
};

// Grab Gemini's text output
let raw = $json.choices[0].message.content;

// Strip markdown fences if Gemini added them
raw = raw.replace(/```json/g, '').replace(/```/g, '').trim();

// Parse the JSON string into real fields
const parsed = JSON.parse(raw);

return {
  score: parsed.score,
  reasoning: parsed.reasoning,
  talking_points: parsed.talking_points,
  // carry the company data forward for the email step
  company: $('Apollo HTTP Request').item.json.body.organization
};

