// Slack sends the click as a JSON string in body.payload
const payload = JSON.parse($json.body.payload);

return {
  action: payload.actions[0].action_id,        // "approve_lead" or "regenerate_lead"
  domain: payload.actions[0].value,             // "razorpay.com"
  user: payload.user.username,                  // who clicked
  response_url: payload.response_url,           // to update the message
  channel: payload.channel.id,
  message_ts: payload.message.ts
};

