parameters.jsCode:
// Parse the regenerated email from Groq
let raw = $json.choices[0].message.content;
raw = raw.replace(/```json/g, '').replace(/```/g, '').trim();
const email = JSON.parse(raw);

// Pull the lead's row data forward (from the Get Row node on this branch)
const row = $('Get row(s) in sheet1').item.json;

return {
  subject: email.subject,
  body: email.body,
  company: row.Company,
  score: row.Score,
  reasoning: row.Reasoning,
  domain: row.Domain
};

const org = $json.body.organization;

return {
  trimmed: {
    name: org.name,
    industry: org.industry,
    employees: org.estimated_num_employees,
    annual_revenue: org.annual_revenue_printed,
    total_funding: org.total_funding_printed,
    founded_year: org.founded_year,
    description: org.short_description,
    keywords: (org.keywords || []).slice(0, 10),
    primary_domain: org.primary_domain
  },
  // keep the full org too, in case downstream needs it
  fullOrg: org
};

const d = $('Parse the re-draft').item.json;

return {
  slackBody: {
    channel: "#sponsor-leads",
    text: "Regenerated draft for " + d.company,
    blocks: [
      { type: "section", text: { type: "mrkdwn", text: "*Regenerated Draft — " + d.company + " (" + d.score + ")*" } },
      { type: "section", text: { type: "mrkdwn", text: "*Subject:* " + d.subject } },
      { type: "section", text: { type: "mrkdwn", text: "*Email:*\n" + String(d.body).split("\n").map(l => l.trim()).filter(l => l).join("\n").slice(0, 2800) } },
      { type: "actions", elements: [
        { type: "button", text: { type: "plain_text", text: "Approve" }, style: "primary", action_id: "approve_lead", value: d.domain },
        { type: "button", text: { type: "plain_text", text: "Regenerate" }, style: "danger", action_id: "regenerate_lead", value: d.domain }
      ]}
    ]
  }
};

